xpath.script:
document.addEventListener('DOMContentLoaded', function() {
    // Replace logo
    var logo = document.querySelector('.navbar-brand img, a.navbar-brand img, #logo img, .o_logo img');
    if (logo) {
        logo.src = '/hr_recruitment_application_extended/static/src/img/logo.svg';
        logo.alt = 'SurePay';
        logo.style.maxHeight = '50px';
        logo.style.width = 'auto';
    }

    // Hide footer
    var footer = document.querySelector('footer, .o_footer, #footer');
    if (footer) {
        footer.style.display = 'none';
    }

    // Simplify navigation menu (optional - uncomment if needed)
    /*
    var menu = document.querySelector('#top_menu, .o_menu_systray, .o_main_navbar');
    if (menu) {
        menu.innerHTML = `



                    Home



                    Jobs



                    Sign In


        `;
    }
    */
});
